export const meta = {
  name: 'qa-session-store',
  description: 'QA workflow: semantic search for session store question',
  phases: [
    { title: 'SemanticSearch', detail: 'Search knowledge for session store DB vs HIDDEN' },
    { title: 'ReadSections', detail: 'Read selected sections' },
  ],
}

phase('SemanticSearch')
const searchResult = await agent(
  `Execute semantic search for this question and return results as structured data.

Question: "入力→確認→完了画面間でセッション変数を保持するとき、DBストアとHIDDENストアの使い分けはどうすればいい？（処理方式: ウェブアプリケーション）（目的: 仕組み・動作を理解したい）"

Working directory: /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6

Read the file workflows/semantic-search.md to understand the search process, then execute it.

The knowledge files are in: /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/knowledge/

Return a JSON object with:
{
  "selected_pages": [{"path": "...", "reason": "..."}],
  "excluded_pages": [{"path": "...", "reason": "..."}],
  "selected_sections": [{"file": "...", "section_id": "...", "relevance": "high|partial", "reason": "..."}],
  "excluded_sections": [{"file": "...", "section_id": "...", "reason": "..."}]
}`,
  {
    label: 'semantic-search',
    phase: 'SemanticSearch',
    schema: {
      type: 'object',
      properties: {
        selected_pages: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              path: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['path', 'reason']
          }
        },
        excluded_pages: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              path: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['path', 'reason']
          }
        },
        selected_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              file: { type: 'string' },
              section_id: { type: 'string' },
              relevance: { type: 'string', enum: ['high', 'partial'] },
              reason: { type: 'string' }
            },
            required: ['file', 'section_id', 'relevance', 'reason']
          }
        },
        excluded_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              file: { type: 'string' },
              section_id: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['file', 'section_id', 'reason']
          }
        }
      },
      required: ['selected_pages', 'excluded_pages', 'selected_sections', 'excluded_sections']
    }
  }
)

phase('ReadSections')

// Select up to 10 sections: high first, then partial
const highSections = searchResult.selected_sections.filter(s => s.relevance === 'high')
const partialSections = searchResult.selected_sections.filter(s => s.relevance === 'partial')
const sectionsToRead = [...highSections, ...partialSections].slice(0, 10)

log(`Reading ${sectionsToRead.length} sections (${highSections.length} high, ${Math.min(partialSections.length, 10 - highSections.length)} partial)`)

const readArgs = sectionsToRead.map(s => `"${s.file}:${s.section_id}"`).join(' ')

const sectionsContent = await agent(
  `Run the following bash command and return the COMPLETE output verbatim (do not truncate or summarize):

cd /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6
bash scripts/read-sections.sh ${readArgs}

Return the complete raw output as a single string field "content".`,
  {
    label: 'read-sections',
    phase: 'ReadSections',
    schema: {
      type: 'object',
      properties: {
        content: { type: 'string' }
      },
      required: ['content']
    }
  }
)

return {
  searchResult,
  sectionsToRead,
  sectionsContent: sectionsContent.content
}

